   266		private startBackgroundLoad(repoPath: string): void {
   267			const generation = this.loadGeneration;
   268			this.loadState = { kind: "loading" };
   269			const startTime = Date.now();
   270			const mode = shouldShowLiveSessions(this.workspaceState) ? "live" : "checkpoint";
   271			this.debug(`startBackgroundLoad: gen=${generation}, mode=${mode}, timeout=${LOAD_TIMEOUT_MS}ms`);
   272	
   273			const work = shouldShowLiveSessions(this.workspaceState)
   274				? this.loadLiveSessions(repoPath).then((cards) => cards.map(adaptLiveCard))
   275				: this.loadCheckpointSessions(repoPath, this.selectedCheckpointSelection?.checkpointIds ?? []).then((cards) => cards.map(adaptCheckpointSessionCard));
   276			const timeout = new Promise<never>((_resolve, reject) => {
   277				setTimeout(() => reject(new Error("Session load timed out")), LOAD_TIMEOUT_MS);
   278			});
   279	
   280			Promise.race([work, timeout])
   281				.then((cards) => {
   282					const elapsed = Date.now() - startTime;
   283					if (this.loadGeneration !== generation) {
   284						this.debug(`startBackgroundLoad: stale gen=${generation} (current=${this.loadGeneration}), discarding ${cards.length} cards after ${elapsed}ms`);
   285						return;
   286					}
   287	
   288					const sortedCards = sortCards(cards);
   289					this.debug(`startBackgroundLoad: success, gen=${generation}, ${cards.length} cards in ${elapsed}ms`);
   290					this.loadState = { kind: "loaded", cards: sortedCards };
   291					this.changeEmitter.fire();
   292				})
   293				.catch((error) => {
   294					const elapsed = Date.now() - startTime;
   295					if (this.loadGeneration !== generation) {
   296						this.debug(`startBackgroundLoad: stale gen=${generation} (current=${this.loadGeneration}), ignoring error after ${elapsed}ms: ${error}`);
   297						return;
